t.t:
.form-card { background: var(--bg-card); border: 1px solid var(--border); border-radius: 12px; padding: 28px; max-width: 640px; }
.form-card h2 { font-family: 'Source Serif 4', serif; font-size: 20px; color: var(--primary); margin-bottom: 24px; padding-bottom: 16px; border-bottom: 1px solid var(--border); }
.form-group { display: flex; flex-direction: column; gap: 5px; margin-bottom: 16px; }
.form-group label { font-size: 13px; font-weight: 500; color: var(--text-primary); }
.form-group input, .form-group select, .form-group textarea { padding: 9px 12px; border: 1px solid var(--border); border-radius: 6px; font-size: 13.5px; font-family: inherit; color: var(--text-primary); background: var(--bg-card); outline: none; transition: border 0.15s; }
.form-group input:focus, .form-group select:focus, .form-group textarea:focus { border-color: var(--primary); box-shadow: 0 0 0 3px rgba(15,76,129,0.08); }
.form-group textarea { resize: vertical; min-height: 120px; }
.msg-success { display:none; background: var(--action-light); border: 1px solid var(--action); border-radius: 8px; padding: 14px 18px; color: var(--action-dark); font-size: 14px; margin-top: 16px; }
.msg-error   { display:none; background: #FAECE7; border: 1px solid #D85A30; border-radius: 8px; padding: 14px 18px; color: #7A2010; font-size: 14px; margin-top: 16px; }

t.script:
async function criarOportunidade() {
    const btn = document.querySelector('.btn-action');
    const nome = document.getElementById('f-name').value.trim();

    if (!nome) {
        mostrarErro('O título é obrigatório.');
        return;
    }

    btn.disabled = true;
    btn.textContent = 'A criar...';

    // CORRECÇÃO: envia com wrapper jsonrpc que o Odoo espera
    const response = await fetch('/api/oportunidades/create', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
            jsonrpc: '2.0',
            method: 'call',
            id: 1,
            params: {
                name:             nome,
                company_name:     document.getElementById('f-company').value.trim(),
                opportunity_type: document.getElementById('f-type').value,
                description:      document.getElementById('f-desc').value.trim(),
            }
        })
    });

    const json = await response.json();
    const result = json.result;

    if (result && result.success) {
        document.getElementById('msg-success').style.display = 'block';
        document.getElementById('msg-error').style.display   = 'none';
        document.getElementById('f-name').value    = '';
        document.getElementById('f-company').value = '';
        document.getElementById('f-desc').value    = '';
    } else {
        mostrarErro(result ? result.message : 'Erro de comunicação com o servidor.');
    }

    btn.disabled = false;
    btn.textContent = 'Criar Oportunidade';
}

function mostrarErro(msg) {
    const el = document.getElementById('msg-error');
    el.textContent = '❌ ' + msg;
    el.style.display = 'block';
    document.getElementById('msg-success').style.display = 'none';
}
